update exercises set name = 'Negativas - Fuerza', description = 'Realiza negativas dentro de un estímulo de fuerza. Objetivo: Desarrollar fuerza de tracción en dorsales, bíceps y antebrazos, mejorando tu capacidad de traccionar y controlar los movimientos de escalada. Descanso: 3 min entre series' where name = 'Negativas - Fuerza';
update exercises set name = 'Activación a Un Brazo - Levantamientos - Fuerza', description = 'Completaras la activación a un brazo (levantamientos) dentro de un estímulo de fuerza. Objetivo: Desarrollar fuerza de tracción en estabilizadores escapulares y dorsales, mejorando tu capacidad de traccionar y controlar los movimientos de escalada. Descanso: 3 min entre series' where name = 'Activacion a Un Brazo - Levantamientos - Fuerza';
update exercises set name = 'Activación a Un Brazo - ISO - 10 s', description = 'Múltiples series de activaciones a un brazo - sujeciones isométricas de 10 s. Objetivo: Construir fuerza isométrica máxima de tracción en estabilizadores escapulares y dorsales, transfiriendose directamente a la capacidad de lock off en la pared. Descanso: 3 min entre series' where name = 'Activacion a Un Brazo - ISO - 10 s';
update exercises set name = 'Negativas a Un Brazo - Fuerza Máxima', description = 'Completaras las negativas a un brazo dentro de un estímulo de fuerza máxima. Objetivo: Reclutar la fuerza de tracción máxima en dorsales, bíceps y antebrazos, construyendo la fuerza de alto nivel necesaria para movimientos potentes en terreno vertical pronunciado. Descanso: 3 min entre series' where name = 'Negativas a Un Brazo - Fuerza Maxima';
update exercises set name = 'Negativas a Un Brazo - Fuerza', description = 'Completa las negativas a un brazo dentro de un estímulo de fuerza. Objetivo: Desarrollar fuerza de tracción en dorsales, bíceps y antebrazos, mejorando tu capacidad de traccionar y controlar los movimientos de escalada. Descanso: 3 min entre series' where name = 'Negativas a Un Brazo - Fuerza';
update exercises set name = 'Flexiones a Un Brazo - Fuerza', description = 'Completaras las flexiones a un brazo dentro de un estímulo de fuerza. Objetivo: Desarrollar fuerza de empuje en pecho, tríceps y hombros, equilibrando las demandas dominantes de tracción de la escalada y protegiendo la salud del hombro. Descanso: 3 min entre series' where name = 'Flexiones a Un Brazo - Fuerza';
update exercises set name = 'Dominada a Un Brazo - Fuerza Máxima', description = 'Realiza la dominada a un brazo dentro de un estímulo de fuerza máxima. Objetivo: Reclutar la fuerza de tracción máxima en dorsales, bíceps, antebrazos y core, construyendo la fuerza de alto nivel necesaria para movimientos potentes en terreno vertical pronunciado. Descanso: 3 min entre series' where name = 'Dominada a Un Brazo - Fuerza Maxima';
update exercises set name = 'Dominada a Un Brazo - Fuerza', description = 'Completaras la dominada a un brazo dentro de un estímulo de fuerza. Objetivo: Desarrollar fuerza de tracción en dorsales, bíceps, antebrazos y core, mejorando tu capacidad de traccionar y controlar los movimientos de escalada. Descanso: 3 min entre series' where name = 'Dominada a Un Brazo - Fuerza';
update exercises set name = 'Generación de Potencia', description = 'Generación de Potencia: un entrenamiento de tracción con varios ejercicios y múltiples series de cada uno. Objetivo: Desarrollar fuerza de tracción equilibrada en múltiples patrones de movimiento, construyendo la fuerza del tren superior esencial para la escalada. Descanso: 3 min entre series' where name = 'Generacion de Potencia';
update exercises set name = 'Flexiones de Potencia', description = 'Este entrenamiento se centra en flexiones de potencia. Objetivo: Construir fuerza de empuje máxima en pecho, tríceps y hombros, manteniendo el equilibrio muscular alrededor de la articulación del hombro y reduciendo el riesgo de lesión. Descanso: 5 min entre series' where name = 'Flexiones de Potencia';
update exercises set name = 'Tracciones de Potencia', description = 'Completa tracciones de potencia en varias series. Objetivo: Reclutar la fuerza de tracción máxima en dorsales, bíceps y antebrazos, construyendo la fuerza de alto nivel necesaria para movimientos potentes en terreno vertical pronunciado. Descanso: 5 min entre series' where name = 'Tracciones de Potencia';
update exercises set name = 'Powerlifting', description = 'Powerlifting: un entrenamiento de tren inferior con varios ejercicios y múltiples series de cada uno. Objetivo: Construir fuerza y potencia del tren inferior de forma completa, apoyando un trabajo de pies fuerte, movimiento dinámico y prevención de lesiones para la escalada. Descanso: 3 min entre series' where name = 'Powerlifting';
update exercises set name = 'Flexiones - Fuerza', description = 'Completa flexiones dentro de un estímulo de fuerza. Objetivo: Empujar hacia arriba a través del pecho, tríceps y hombros anteriores desarrolla la fuerza detras de los mantle y los movimientos de compresión, manteniendo el equilibrio muscular. Descanso: 3 min entre series' where name = 'Flexiones - Fuerza';
update exercises set name = 'Rotaciones de Hombro en Prono - Fuerza', description = 'Completa rotaciones de hombro en prono dentro de un estímulo de fuerza. Objetivo: Desarrollar fuerza de tracción en el manguito rotador y deltoides posteriores, mejorando tu capacidad de traccionar y controlar los movimientos de escalada. Descanso: 3 min entre series' where name = 'Rotaciones de Hombro en Prono - Fuerza';
update exercises set name = 'Secuencia TRX IYT en Prono - Repeticiones Medias', description = 'Completaras la secuencia TRX IYT en prono dentro de un estímulo de repeticiones moderadas. Objetivo: Desarrollar fuerza de empuje en deltoides posteriores, trapecio inferior y manguito rotador, equilibrando las demandas dominantes de tracción de la escalada y protegiendo la salud del hombro. Descanso: 3 min entre series' where name = 'Secuencia TRX IYT en Prono - Repeticiones Medias';
update exercises set name = 'Pseudo Flexiones - Fuerza', description = 'Completa flexiones dentro de un estímulo de fuerza. Objetivo: La fuerza de empuje repetible y exigente proviene de entrenar en este rango. Con los hombros y el serrato involucrados en el movimiento por la inclinación hacia adelante, desarrollas la fuerza detras del press en placa, los tirones de gastón y el empuje dominado por el hombro en terreno técnico. Descanso: 3 min entre series' where name = 'Pseudo Flexiones - Fuerza';
update exercises set name = 'Superserie de Potencia de Tracción', description = 'Superserie de Potencia de Tracción: un entrenamiento de tracción con varios ejercicios y múltiples series de cada uno. Objetivo: Desarrollar fuerza de tracción equilibrada en múltiples patrones de movimiento, construyendo la fuerza del tren superior esencial para la escalada. Descanso: 3 min entre series' where name = 'Superserie de Potencia de Traccion';
update exercises set name = 'Dominadas - Test de Fuerza', description = 'En este entrenamiento completaras dominadas como prueba de tu fuerza actual. Objetivo: Reclutar la fuerza de tracción máxima en dorsales, bíceps y antebrazos, construyendo la fuerza de alto nivel necesaria para movimientos potentes en terreno vertical pronunciado. Descanso: 3 min entre series' where name = 'Dominadas - Test de Fuerza';
update exercises set name = 'Dominadas - Fuerza', description = 'Completaras las dominadas dentro de un estímulo de fuerza. Objetivo: Desarrollar fuerza de tracción en dorsales, bíceps y antebrazos, mejorando tu capacidad de traccionar y controlar los movimientos de escalada. Descanso: 3 min entre series' where name = 'Dominadas - Fuerza';
update exercises set name = 'Rack Pull - Fuerza', description = 'Este entrenamiento se centra en el rack pull dentro de un estímulo de fuerza. Objetivo: Desarrollar fuerza del tren inferior en espalda alta, trapecios y antebrazos, mejorando tu capacidad de generar fuerza a través de pies y piernas mientras escalas. Descanso: 3 min entre series' where name = 'Rack Pull - Fuerza';
update exercises set name = 'Curl Inverso - Fuerza', description = 'Completaras el curl inverso dentro de un estímulo de fuerza. Objetivo: Desarrollar fuerza de tracción en braquiorradial y extensores del antebrazo, mejorando tu capacidad de traccionar y controlar los movimientos de escalada. Descanso: 3 min entre series' where name = 'Curl Inverso - Fuerza';
update exercises set name = 'Flexiones Escapulares - Repeticiones Medias', description = 'Completaras las flexiones escapulares dentro de un estímulo de repeticiones moderadas. Objetivo: Desarrollar fuerza de empuje en pecho, tríceps y hombros, mejorando tu capacidad de empujar y estabilizar los movimientos de escalada. Descanso: 3 min entre series' where name = 'Flexiones Escapulares - Repeticiones Medias';
