update exercises set name = 'Activación a Dos Brazos - Levantamiento - Fuerza', description = 'Este entrenamiento se centra en la activación a dos brazos (levantamiento) dentro de un estímulo de fuerza. Objetivo: Desarrollar fuerza de tracción en estabilizadores escapulares y dorsales, mejorando tu capacidad de traccionar y controlar los movimientos de escalada. Descanso: 3 min entre series' where name = 'Activacion a Dos Brazos - Levantamiento - Fuerza';
