update exercises set name = 'Zancada Caminando con Mancuernas - Fuerza', description = 'Completa la zancada caminando con mancuernas dentro de un estímulo de fuerza. Objetivo: Desarrollar fuerza del tren inferior en cuádriceps, glúteos e isquiotibiales, mejorando tu capacidad de generar fuerza a través de pies y piernas mientras escalas. Descanso: 3 min entre series' where name = 'Zancada Caminando con Mancuernas - Fuerza';
update exercises set name = 'Tracciones Anchas - Fuerza', description = 'Completaras las tracciones anchas dentro de un estímulo de fuerza. Objetivo: Desarrollar fuerza de tracción en dorsales, bíceps y antebrazos, mejorando tu capacidad de traccionar y controlar los movimientos de escalada. Descanso: 3 min entre series' where name = 'Tracciones Anchas - Fuerza';
update exercises set name = '4x4', description = 'Escala 4 boulders seguidos con poco o ningun descanso entre problemas, luego descansa antes de repetir durante varias series. Objetivo: Desarrollar la potencia aeróbica mediante esfuerzos de alta intensidad con descanso limitado, usando movimiento variado de boulder para impulsar el rendimiento sostenido. Descanso: 5 min entre series' where name = '4x4';
update exercises set name = '6 en 6', description = 'Completa 6 boulders al minuto en varias series. El marco de tiempo comprimido genera fatiga rápida. Objetivo: Desarrollar producción anaeróbica repetida con cada boulder completado al minuto. Descanso: 5 min entre series' where name = '6 en 6';
update exercises set name = 'Test de Repeticiones al 60%', description = 'Cuelgate al 60% de tu máximo a dos brazos con un ciclo de 7 segundos activo, 3 segundos de descanso, y continua hasta el fallo. Registra tu tiempo total hasta el agotamiento. Objetivo: Testear y establecer una referencia de tu capacidad de resistencia del antebrazo a una intensidad submáxima estandarizada.' where name = 'Test de Repeticiones al 60%';
update exercises set name = 'Proyecto de Capacidad Anaeróbica', description = 'Repite un boulder específico de proyecto o replica en varias series, escalando con enfoque de rendimiento. Objetivo: Transferir las ganancias de capacidad anaeróbica a las demandas reales o específicas del proyecto. Descanso: 5 min entre series' where name = 'Proyecto de Capacidad Anaerobica';
update exercises set name = 'Dobles de Boulder', description = 'Escala un boulder difícil, descanso breve, luego repitelo de inmediato. Completa varias series de dobles. Objetivo: Desarrollar la capacidad anaeróbica y la habilidad de mantener la intensidad en esfuerzos repetidos de alta potencia. Descanso: 4 min entre series' where name = 'Dobles de Boulder';
update exercises set name = 'Kilometraje de Boulder - Intervalos Forzados', description = 'Completa un número alto de boulders de rango medio en varias series con descansos cortos, asegurando una amplia variedad de movimiento. Objetivo: Impulsar la potencia aeróbica completando un alto volumen de boulders de intensidad media a alta bajo fatiga. Descanso: 10 min entre series' where name = 'Kilometraje de Boulder - Intervalos Forzados';
update exercises set name = 'Triples de Boulder', description = 'Escala un boulder difícil 3 veces por serie con descanso corto entre repeticiones, completando varias series. Objetivo: Desarrollar la capacidad anaeróbica mediante esfuerzos repetidos de alta intensidad que acumulan fatiga a través de las repeticiones y del transcurso de la sesión. Descanso: 5 min entre series' where name = 'Triples de Boulder';
update exercises set name = '30 Movimientos Fraccionados', description = 'Divide una ruta o circuito de 30 movimientos en 3 secciones de 10 movimientos, descansando 20 segundos entre secciones. Descansa 6 minutos entre vueltas completas. Objetivo: Entrenar el rendimiento en escalada sostenida dividiendo una ruta de nivel límite en secciones completables. Descanso: 6 min entre series' where name = '30 Movimientos Fraccionados';
update exercises set name = 'Boulders Extendidos', description = 'Repite un boulder largo de 16 movimientos en varias series. Espera estar luchando hacia el final. Objetivo: Impulsar la tolerancia a secuencias sostenidas de alta intensidad que conectan el boulder con el esfuerzo de la longitud de una ruta. Descanso: 5 min entre series' where name = 'Boulders Extendidos';
update exercises set name = '5 Series Más Difíciles', description = 'Escala 5 rutas o circuitos difíciles de 30-40 movimientos de más fácil a más difícil. Objetivo: Mejorar la potencia aeróbica mediante esfuerzos de longitud de ruta desafiantes que te preparan para las demandas de la escalada deportiva difícil. Descanso: 10 min entre series' where name = '5 Series Mas Dificiles';
update exercises set name = 'Boulders Enlazados', description = 'Repite un boulder largo bien ensayado (alrededor de 14 movimientos) en varias series. Objetivo: Mejorar la tolerancia a secuencias sostenidas de alta intensidad que exigen un esfuerzo prolongado. Descanso: 5 min entre series' where name = 'Boulders Enlazados';
update exercises set name = 'A Vista', description = 'Intenta 4 rutas en o cerca de tu nivel a vista de punta, dedicando tiempo a leer la ruta y prepararte antes de cada intento unico. Objetivo: Entrenar la potencia aeróbica junto con las habilidades tácticas y psicológicas necesarias para rendir en intentos a vista. Descanso: 20 min entre series' where name = 'A Vista';
update exercises set name = 'Dobles de Ruta', description = 'Escala una ruta difícil, descansa brevemente en la pared o baja, luego repitela de inmediato. Completa 5 vueltas dobles con descanso completo entre series. Objetivo: Construir potencia aeróbica sostenida replicando esfuerzos más largos, asegurando un alto volumen de escalada fatigante. Descanso: 10 min entre series' where name = 'Dobles de Ruta';
update exercises set name = 'Proyectando Rutas', description = 'Dedica el entrenamiento a intentar rutas en el límite de tu capacidad, ya sean proyectos o escaladas nuevas difíciles. Apunta a 150-250 movimientos en total. Objetivo: Desarrollar la resistencia de potencia de alto nivel intentando rutas difíciles, construyendo la capacidad de rendir a este nivel.' where name = 'Proyectando Rutas';
update exercises set name = 'Pirámide de Rutas', description = 'Escala 8 rutas en pirámide, empezando fácil, subiendo hasta tu nivel más difícil, y luego bajando de nuevo. Si tienes menos series, detente en la cima. Objetivo: Entrenar la potencia aeróbica completando escalada de rutas de alto volumen a través de intensidades ascendentes y descendentes. Descanso: 10 min entre series' where name = 'Piramide de Rutas';
update exercises set name = 'Eficiencia en Board', description = 'Refina la beta y elimina movimientos innecesarios en problemas de board que ya conoces. Enfocate en escalar de la manera más limpia y eficiente posible. Objetivo: Aumentar la eficiencia técnica y la economía energética en terreno vertical pronunciado sin necesidad de ganar fuerza.' where name = 'Eficiencia en Board';
update exercises set name = 'Esfuerzos Máximos en Board', description = 'Trabaja a verdadera intensidad de alto nivel en un training board, intentando problemas que tomaran varios entrenamientos completar. Objetivo: Aumentar la fuerza máxima y la producción de potencia en terreno de board pronunciado.' where name = 'Esfuerzos Maximos en Board';
update exercises set name = 'Esfuerzos Máximos en Board - Extendido', description = 'Un entrenamiento extendido de board a verdadera intensidad de alto nivel, con más tiempo para trabajar problemas límite y acumular intentos de calidad. Objetivo: Aumentar la fuerza máxima y la producción de potencia con un mayor volumen de esfuerzo de alto nivel.' where name = 'Esfuerzos Maximos en Board - Extendido';
update exercises set name = 'Pausas en Board', description = 'En cada movimiento de un problema de board pronunciado, suelta los pies y manten 3 segundos antes de volver a colocarlos. Manten el control en todo momento. Objetivo: Desarrollar fuerza de contacto, estabilidad de hombro y control posicional bajo carga. Descanso: 5 min entre series' where name = 'Pausas en Board';
update exercises set name = 'Encadenando en Board', description = 'Intenta problemas de board justo por debajo de tu límite que puedas completar en pocos intentos. Apunta a encadenes de calidad más que a proyectos de largo plazo. Objetivo: Construir confianza y capacidad de rendimiento en terreno de board pronunciado mediante la ejecución exitosa de problemas difíciles.' where name = 'Encadenando en Board';
update exercises set name = 'Sesión de Board', description = 'Escala problemas difíciles en un training board con 3 intentos por problema y recuperación completa entre series. Objetivo: Construir fuerza y potencia de alto nivel mientras mejoras tu capacidad de ejecutar movimientos difíciles en terreno de board pronunciado. Descanso: 6 min entre series' where name = 'Sesion de Board';
update exercises set name = 'Volumen de Board', description = 'Acumula un número alto de problemas de board desafiantes a intensidad submáxima, completando cada uno en 1-3 intentos antes de continuar. Objetivo: Construir capacidad de trabajo y resistencia de fuerza en terreno pronunciado mediante un esfuerzo constante y de alto volumen.' where name = 'Volumen de Board';
update exercises set name = 'Circuitos de Boulder', description = 'Sigue un circuito o elige boulders dentro de un rango de grado dado, trabajando problemas justo por encima de tu nivel a vista con series estructuradas. Objetivo: Construir fuerza submáxima y variedad de movimiento mediante un esfuerzo consistente y repetible a través de una gama de problemas. Descanso: 6 min entre series' where name = 'Circuitos de Boulder';
update exercises set name = 'Enfoque de Boulder', description = 'Enfocate en un tema técnico o estilo de movimiento específico durante todo el entrenamiento, según indique tu entrenador. Ejecuta con precisión. Objetivo: Abordar debilidades técnicas individuales mientras se mantiene un estímulo de fuerza. Descanso: 3 min entre series' where name = 'Enfoque de Boulder';
update exercises set name = 'Esfuerzos Máximos de Boulder', description = 'Intenta problemas de boulder en el límite de tu capacidad con recuperación completa entre intentos. Los problemas pueden tomar varios entrenamientos completar. Objetivo: Aumentar la fuerza máxima y la producción de potencia.' where name = 'Esfuerzos Maximos de Boulder';
update exercises set name = 'Kilometraje de Boulder', description = 'Completa 20 boulders en una hora a una intensidad desafiante pero manejable, apuntando a encadenar o completar cada uno en dos intentos. Objetivo: Construir capacidad y tolerancia para boulder sostenido de alto volumen a una intensidad media controlada.' where name = 'Kilometraje de Boulder';
update exercises set name = 'Juego de Boulder', description = 'Experimenta con el movimiento en un estímulo de baja presión creando o modificando problemas. Prueba estilos, betas y posiciones corporales poco familiares. Objetivo: Expandir el vocabulario de movimiento, la coordinación y la resolución creativa de problemas.' where name = 'Juego de Boulder';
update exercises set name = 'Pirámide de Boulder', description = 'Escala problemas progresivamente más difíciles hasta tu máximo, luego trabaja de vuelta hacia grados más fáciles. Si tienes menos series, detente en la cima. Objetivo: Desarrollar la fuerza y el manejo de la fatiga mediante variación de intensidad controlada a través de una pirámide estructurada. Descanso: 2 min 30 s entre series' where name = 'Piramide de Boulder';
update exercises set name = 'Encadenando Boulder', description = 'Intenta problemas que sean difíciles pero alcanzables en pocos intentos. Prioriza los encadenes exitosos y la ejecución precisa. Objetivo: Reforzar la consistencia de rendimiento mientras se construye fuerza y potencia submáxima.' where name = 'Encadenando Boulder';
update exercises set name = 'Campus - 3 Movimientos', description = 'Realiza 3 movimientos máximos de campus por serie en varias series, enfocandote en velocidad y contacto controlado en cada peldano. Objetivo: Aumentar la potencia de tracción máxima y la fuerza de contacto mediante secuencias de campus máximas extendidas. Descanso: 3 min entre series' where name = 'Campus - 3 Movimientos';
update exercises set name = 'Sesión de Competencia - Final', description = 'Simula una competencia estilo final con 4 minutos por problema y recuperación completa entre boulders. Maximiza la calidad por intento. Objetivo: Desarrollar el rendimiento máximo bajo demanda psicológica máxima y presión de tiempo. Descanso: 10 min entre series' where name = 'Sesion de Competencia - Final';
update exercises set name = 'Sesión de Competencia - Semifinal', description = 'Replica las demandas de una competencia de semifinal con 5 minutos por problema y descanso estructurado. Escala bajo presión. Objetivo: Mejorar la compostura, la precisión y la ejecución a alta intensidad bajo restricciones estilo competencia. Descanso: 5 min entre series' where name = 'Sesion de Competencia - Semifinal';
update exercises set name = 'Eliminados', description = 'Escala problemas con presas eliminadas para forzar soluciones creativas y dinámicas. Adopta la resolución de problemas y el movimiento poco familiar. Objetivo: Desarrollar coordinación, precisión y adaptabilidad mediante escalada restringida. Descanso: 2 min entre series' where name = 'Eliminados';
update exercises set name = 'Encadenando a Vista (Flash)', description = 'Comprometete por completo con esfuerzos de un solo intento a vista (flash) en problemas de tu grado de flash a través de una variedad de estilos. Lee la ruta con cuidado, luego da el 100%. Objetivo: Mejorar la capacidad de flash, la toma de decisiones y la ejecución bajo alta presión. Descanso: 3 min entre series' where name = 'Encadenando a Vista (Flash)';
update exercises set name = 'Esfuerzos Máximos de Boulder Sin Pies', description = 'Campusea los problemas de boulder de 4 movimientos más difíciles posibles en presas grandes sin usar los pies. Usa movimientos potentes y evita los lock offs estáticos. Objetivo: Aumentar la fuerza de tracción, la tensión y la precisión a intensidad máxima sin asistencia del tren inferior. Descanso: 10 min entre series' where name = 'Esfuerzos Maximos de Boulder Sin Pies';
update exercises set name = 'Referencias de MoonBoard', description = 'Intenta problemas de referencia desafiantes de MoonBoard con 3 intentos por problema y recuperación completa entre series. Objetivo: Mejorar la fuerza de tracción máxima y la resolución rápida de problemas en terreno pronunciado y estandarizado. Descanso: 6 min entre series' where name = 'Referencias de MoonBoard';
update exercises set name = 'Intervalos de Fuerza', description = 'Repite boulders difíciles pero submaximos en series estructuradas con recuperación completa. Opera cerca de tu umbral de fuerza superior en todas las series. Objetivo: Aumentar la resistencia de fuerza y la producción de fuerza repetible. Descanso: 5 min entre series' where name = 'Intervalos de Fuerza';
update exercises set name = 'Tensión - Manos Fijas', description = 'Manten las manos fijas en dos presas mientras trasladas los pies a través de la pared en terreno pronunciado, generando el movimiento desde el tren inferior y el core. Objetivo: Desarrollar el manejo de la tensión, la fuerza posicional y la transferencia eficiente de fuerza a través de los pies en terreno pronunciado. Descanso: 3 min entre series' where name = 'Tension - Manos Fijas';
update exercises set name = 'Flexibilidad de Tobillo', description = 'Un entrenamiento guiado de estiramientos de gemelos, elevaciones de talón tipo burro y estiramientos de pescador para aumentar el rango de movimiento del tobillo. Objetivo: Mejorar la dorsiflexión del tobillo para que puedas bajar más el talón en las presas de pie, aumentando el área de contacto y la fricción para escalada en placa y vertical. Descanso: 60 s entre series' where name = 'Flexibilidad de Tobillo';
update exercises set name = 'Rotación Externa con Banda - Contrae y Relaja', description = 'Múltiples series de ciclos de contrae y relaja. Objetivo: Usar técnicas de contrae y relaja para mejorar el rango de movimiento en el manguito rotador y el hombro posterior, mejorando la calidad del movimiento y la salud del hombro para la escalada. Descanso: 1 min 30 s entre series', equipment_required = '["Banda elástica"]' where name = 'Rotacion Externa con Banda - Contrae y Relaja';
update exercises set name = 'Elevación en Barra - Lateral', description = 'Realiza elevaciones laterales de pierna controladas para fortalecer los abductores de cadera cerca de su rango final de movimiento. Objetivo: Construir fuerza del abductor de cadera en el rango final, mejorando la elevación lateral activa de la pierna para colocaciones de pie amplias mientras escalas. Descanso: 60 s entre series' where name = 'Elevacion en Barra - Lateral';
update exercises set name = 'Estiramiento de Bíceps - Estático Pasivo', description = 'Manten un estiramiento estático de bíceps usando la posición de tu cuerpo para sostener el estiramiento durante sujeciones cronometradas. Objetivo: Mejorar la flexibilidad de bíceps y codo, reduciendo la rigidez de la escalada y apoyando la extensión completa del brazo en la pared. Descanso: 60 s entre series' where name = 'Estiramiento de Biceps - Estatico Pasivo';
update exercises set name = 'Sentadillas Cosaco - Estiramiento con Tempo', description = 'Realiza sentadillas cosaco siguiendo un temporizador de tempo a través de las fases de bajada, pausa y subida para estirar los aductores y las caderas. Objetivo: Desarrollar movilidad lateral de cadera y flexibilidad de aductores bajo control, mejorando la capacidad de alcanzar presas de pie amplias. Descanso: 1 min 30 s entre series' where name = 'Sentadillas Cosaco - Estiramiento con Tempo';
update exercises set name = 'Pullover de Dorsales con Mancuerna - Estiramiento con Tempo', description = 'Realiza pullovers de dorsales con mancuerna siguiendo un temporizador a través de las fases de bajada, pausa y subida para estirar los dorsales y los hombros. Objetivo: Aumentar la flexibilidad por encima de la cabeza de dorsales y hombros mediante trabajo de tempo cargado, mejorando el alcance y el movimiento por encima de la cabeza en la pared. Descanso: 1 min 30 s entre series' where name = 'Pullover de Dorsales con Mancuerna - Estiramiento con Tempo';
update exercises set name = 'Estiramientos de Dedos - Estático Pasivo', description = 'Múltiples series de estiramientos de dedos pasivos de 60 s. Objetivo: Mejorar la flexibilidad de flexores y extensores de los dedos, apoyando la salud de los dedos y reduciendo el riesgo de lesión por las altas demandas de carga de la escalada. Descanso: 60 s entre series' where name = 'Estiramientos de Dedos - Estatico Pasivo';
update exercises set name = 'Fire Hydrant - Pierna Flexionada - Desarrollo de Fuerza', description = 'Realiza repeticiones de fire hydrant con pierna flexionada para fortalecer los glúteos y los rotadores externos de cadera cerca del rango final de movimiento. Objetivo: Construir fuerza de glúteos y rotadores de cadera en el rango final, mejorando la estabilidad y el control en posiciones de escalada con rotación externa. Descanso: 1 min 30 s entre series' where name = 'Fire Hydrant - Pierna Flexionada - Desarrollo de Fuerza';
update exercises set name = 'Mantenimiento de Flexibilidad', description = 'Una rutina guiada de mantenimiento de cuerpo entero con patadas, pancake, rana, paloma, estiramiento de sofá, estiramiento de gemelo, estiramiento de pecho y estiramiento de dorsal a baja intensidad. Objetivo: Mantener las ganancias de flexibilidad durante semanas de descarga y taper, previniendo la regresión del rango de movimiento sin agregar carga de entrenamiento. Descanso: 5 s entre series' where name = 'Mantenimiento de Flexibilidad';
update exercises set name = 'Flexibilidad de Antebrazo', description = 'Un entrenamiento guiado de estiramientos de extensores y flexores de muñeca para aumentar la flexibilidad de antebrazo y muñeca. Objetivo: Mejorar el rango de movimiento de muñeca y antebrazo, apoyando una mayor variedad de posiciones de presa incluyendo undercuts, gastones y regletas planas. Descanso: 30 s entre series' where name = 'Flexibilidad de Antebrazo';
update exercises set name = 'Rana Supina - Estático Pasivo', description = 'Manten un estiramiento de rana acostado boca arriba, usando la gravedad para asistir la apertura de cadera durante sujeciones cronometradas. Objetivo: Aumentar la flexibilidad de aductores de cadera en una posición asistida, construyendo rango de ingle para posiciones de escalada con piernas opens. Descanso: 60 s entre series' where name = 'Rana Supina - Estatico Pasivo';
update exercises set name = 'Patadas Frontales - Dinámico', description = 'Realiza patadas frontales controladas para estirar activamente los isquiotibiales y flexores de cadera. Objetivo: Construir flexibilidad dinámica de isquiotibiales y potencia de flexores de cadera, mejorando la capacidad de levantar los pies alto frente al cuerpo mientras escalas. Descanso: 60 s entre series' where name = 'Patadas Frontales - Dinamico';
update exercises set name = 'Split Frontal - Nivel 1', description = 'Un entrenamiento de split frontal con varios ejercicios usando peso muerto rumano a una pierna y sujeciones isométricas de zancada larga para desarrollar fuerza y rango mediante estiramientos activo-estáticos. Objetivo: Construir flexibilidad de isquiotibiales y flexores de cadera con fuerza en el rango final, creando una base para la progresión del split frontal y la capacidad de paso alto.' where name = 'Split Frontal - Nivel 1';
update exercises set name = 'Pulsos de Split Frontal - Dinámico', description = 'Realiza repeticiones de pulso controladas manteniendo una profundidad exigente de split frontal para fortalecer los músculos en el rango final. Objetivo: Desarrollar fuerza activa y resistencia muscular a una profundidad de split casi máxima, construyendo rango utilizable para posiciones de escalada. Descanso: 60 s entre series' where name = 'Pulsos de Split Frontal - Dinamico';
update exercises set name = 'Glúteos e Isquiotibiales', description = 'Un entrenamiento guiado de estiramiento de sofá, pancake de pie, postura de paloma y split lateral ISO para aumentar la flexibilidad de glúteos e isquiotibiales. Objetivo: Mejorar el rango de cadera, glúteo e isquiotibial para que puedas colocar los pies más alto en la pared manteniendo las caderas cerca, aumentando la economía de movimiento. Descanso: 60 s entre series' where name = 'Gluteos e Isquiotibiales';
update exercises set name = 'Good Morning Sentado - Estiramiento con Tempo', description = 'Realiza good mornings sentado siguiendo un temporizador de tempo a través de las fases de bajada, pausa y subida para estirar los isquiotibiales. Objetivo: Mejorar la flexibilidad de isquiotibiales y el rango de flexión de tronco mediante trabajo de tempo controlado, apoyando los heel hooks y las colocaciones de pie alto. Descanso: 1 min 30 s entre series' where name = 'Good Morning Sentado - Estiramiento con Tempo';
update exercises set name = 'Estiramiento de Isquiotibiales - Sentado - Estático Pasivo', description = 'Manten un estiramiento de isquiotibiales sentado usando la posición del cuerpo y la gravedad para sostener el estiramiento durante sujeciones cronometradas. Objetivo: Aumentar la flexibilidad de isquiotibiales mediante sujeciones pasivas sostenidas, mejorando el rango de flexión de tronco para heel hooks y colocaciones de pie alto. Descanso: 60 s entre series' where name = 'Estiramiento de Isquiotibiales - Sentado - Estatico Pasivo';
update exercises set name = 'Aductores de Cadera', description = 'Un entrenamiento guiado de mariposa, split lateral ISO, rana y medio split lateral para aumentar la flexibilidad de los aductores de cadera. Objetivo: Mejorar el alcance lateral de la pierna aumentando la flexibilidad de los aductores, ampliando las opciones de presas de pie y la economía de movimiento en la pared. Descanso: 60 s entre series' where name = 'Aductores de Cadera';
update exercises set name = 'Postura de Caballo - ISO - Estático Activo', description = 'Manten una posición de sentadilla de caballo en profundidad mientras usas activamente tus músculos para mantener la postura durante sujeciones cronometradas. Objetivo: Construir flexibilidad de aductores y estabilidad de cadera mediante sujeciones activas, mejorando la capacidad de mantener posturas amplias en la pared. Descanso: 60 s entre series' where name = 'Postura de Caballo - ISO - Estatico Activo';
update exercises set name = 'Zancada Larga ISO - Estático Pasivo', description = 'Manten una posición de zancada larga de forma pasiva, usando la posición del cuerpo y la gravedad para sostener el estiramiento del flexor de cadera durante sujeciones cronometradas. Objetivo: Alargar los flexores de cadera mediante sujeciones pasivas sostenidas, mejorando el rango de extensión de cadera para pasos altos y posiciones de pared pronunciada. Descanso: 60 s entre series' where name = 'Zancada Larga ISO - Estatico Pasivo';
update exercises set name = 'Movilidad Matutina', description = 'Un entrenamiento guiado diario en el piso de giro de sabio, postura de cachorro, estiramiento de gemelo en pared, side runner, postura de paloma y sentadilla yogui para movilidad de cuerpo entero. Objetivo: Construir movilidad mediante la práctica diaria de baja intensidad, reforzando el hábito para apoyar las ganancias de flexibilidad con el tiempo. Descanso: 30 s entre series' where name = 'Movilidad Matutina';
update exercises set name = 'Pancake - Pulsos', description = 'Pulsa hacia un estiramiento profundo de pancake, moviendote a través del arco de tu posición de piernas opens por repeticiones. Objetivo: Aumentar la flexibilidad de isquiotibiales y aductores mediante pulsos dinámicos, mejorando el rango de piernas opens para colocaciones de pie amplias. Descanso: 1 min 30 s entre series' where name = 'Pancake - Pulsos';
update exercises set name = 'Pancake - De Pie - Estático Pasivo', description = 'Manten un estiramiento de pancake de pie con las piernas bien separadas, usando la gravedad para asistir el pliegue hacia adelante durante sujeciones cronometradas. Objetivo: Aumentar la flexibilidad de isquiotibiales y aductores en una posición de piernas opens de pie, apoyando el movimiento de piernas amplias y los pasos altos mientras escalas. Descanso: 60 s entre series' where name = 'Pancake - De Pie - Estatico Pasivo';
update exercises set name = 'Estiramiento de Pecho - Estático Pasivo', description = 'Manten un estiramiento pasivo de pecho usando la gravedad o una superficie externa para sostener la posición de apertura del pecho durante sujeciones cronometradas. Objetivo: Mejorar la flexibilidad de pecho y hombro anterior, reduciendo la rigidez de la escalada y apoyando posiciones de cuerpo abierto en la pared. Descanso: 60 s entre series' where name = 'Estiramiento de Pecho - Estatico Pasivo';
update exercises set name = 'Postura de Paloma - Contrae y Relaja', description = 'Alterna entre contraer y relajar los músculos de la cadera en una postura de paloma para facilitar un estiramiento más profundo con cada ciclo. Objetivo: Mejorar la flexibilidad de glúteo y rotador de cadera usando técnicas FNP, acelerando las ganancias en la rotación externa de cadera para la técnica de escalada. Descanso: 60 s entre series' where name = 'Postura de Paloma - Contrae y Relaja';
update exercises set name = 'Pulsos y Patadas', description = 'Un entrenamiento guiado diario de patadas laterales, patadas frontales y pulsos de pancake para entrenar la flexibilidad dinámica mediante repetición de alta frecuencia. Objetivo: Desarrollar rango activo dinámico mediante ejercicios diarios de patadas y pulsos, construyendo flexibilidad utilizable para el movimiento de escalada.' where name = 'Pulsos y Patadas';
update exercises set name = 'Estiramiento de Cuádriceps - Sentado - Estático Pasivo', description = 'Manten un estiramiento pasivo de cuádriceps en posición sentada, reclinandote hacia atrás para aumentar y sostener el estiramiento durante sujeciones cronometradas. Objetivo: Alargar los cuádriceps y flexores de cadera mediante sujeciones pasivas, mejorando el rango de flexión de rodilla y extensión de cadera para heel hooks y pasos altos. Descanso: 60 s entre series' where name = 'Estiramiento de Cuadriceps - Sentado - Estatico Pasivo';
update exercises set name = 'Estiramiento Revolver - Estático Pasivo', description = 'Manten un estiramiento revolver pasivo en medio split para estirar los dorsales y el costado del torso durante sujeciones cronometradas. Objetivo: Aumentar la flexibilidad de dorsales y tronco lateral, mejorando el alcance lateral y el movimiento por encima de la cabeza en la pared. Descanso: 60 s entre series' where name = 'Estiramiento Revolver - Estatico Pasivo';
update exercises set name = 'Dislocaciones de Hombro - Estiramiento con Tempo', description = 'Realiza pases circulares de hombro usando un palo o banda, siguiendo un tempo para guiar el movimiento a través del rango completo. Objetivo: Aumentar la movilidad de hombro y el rango por encima de la cabeza mediante trabajo de tempo controlado, mejorando el alcance y la libertad de movimiento en la pared. Descanso: 60 s entre series' where name = 'Dislocaciones de Hombro - Estiramiento con Tempo';
update exercises set name = 'Patadas Laterales - Dinámico', description = 'Realiza patadas laterales controladas para estirar activamente los aductores de cadera a través de su rango completo. Objetivo: Desarrollar rango de movimiento lateral dinámico de cadera, mejorando la capacidad de colocar los pies amplios con control mientras escalas. Descanso: 60 s entre series' where name = 'Patadas Laterales - Dinamico';
update exercises set name = 'Split Lateral - Nivel 1', description = 'Un entrenamiento guiado de split lateral usando sujeciones ISO de postura de caballo y estiramientos de pancake de pie para desarrollar fuerza y rango de aductores de cadera mediante trabajo activo y estático. Objetivo: Construir rango de split lateral fundamental y fuerza de aductores sin carga externa, creando una base para una mayor progresión de flexibilidad. Descanso: 10 s entre series' where name = 'Split Lateral - Nivel 1';
update exercises set name = 'Split Lateral ISO - Estático Activo', description = 'Manten una posición de split lateral mientras involucras activamente tus músculos para sostener el estiramiento durante sujeciones cronometradas. Objetivo: Construir fuerza activa y control a la profundidad del split lateral, desarrollando rango de movimiento utilizable para posiciones de escalada amplias. Descanso: 60 s entre series' where name = 'Split Lateral ISO - Estatico Activo';
update exercises set name = 'Test de Split Lateral - Sin Apoyo', description = 'Realiza una sujeción ISO de split lateral sin apoyo para registrar tu rendimiento actual de split lateral, con notas y medidas registradas en el tiempo. Objetivo: Establecer una referencia de tu progreso en split lateral mediante un test estandarizado, permitiendote a ti y a tu entrenador seguir las ganancias de flexibilidad en el tiempo.' where name = 'Test de Split Lateral - Sin Apoyo';
update exercises set name = 'Estiramiento Sleeper - Estático Pasivo', description = 'Manten un estiramiento sleeper acostado de lado, usando la gravedad y el otro brazo para sostener un estiramiento posterior del hombro durante sujeciones cronometradas. Objetivo: Mejorar la flexibilidad posterior del hombro y el rango de rotación interna, reduciendo la rigidez del hombro por la escalada y apoyando una mecanica articular saludable. Descanso: 60 s entre series' where name = 'Estiramiento Sleeper - Estatico Pasivo';
update exercises set name = 'Peso Muerto Rumano a Una Pierna - Estiramiento con Tempo', description = 'Realiza peso muerto rumano a una pierna siguiendo un temporizador de tempo a través de las fases de bajada, pausa y subida para estirar los isquiotibiales. Objetivo: Aumentar la flexibilidad de isquiotibiales a una pierna mediante trabajo de tempo controlado, mejorando el rango de pliegue hacia adelante y la capacidad de heel hook. Descanso: 1 min 30 s entre series' where name = 'Peso Muerto Rumano a Una Pierna - Estiramiento con Tempo';
update exercises set name = 'Sentadillas Split - Estiramiento con Tempo', description = 'Realiza sentadillas split siguiendo un temporizador de tempo a través de las fases de bajada, pausa y subida para estirar los flexores de cadera y cuádriceps. Objetivo: Desarrollar la longitud del flexor de cadera y la flexibilidad de cuádriceps bajo carga, mejorando la zancada profunda y la capacidad de paso alto en la pared. Descanso: 1 min 30 s entre series' where name = 'Sentadillas Split - Estiramiento con Tempo';
update exercises set name = 'Estiramiento de Gemelo en Pared - Estático Pasivo', description = 'Manten un estiramiento pasivo de gemelo usando una pared para sostener la posición de estiramiento durante sujeciones cronometradas. Objetivo: Mejorar la flexibilidad de gemelo y tobillo, permitiendo bajadas de talón más profundas y mejor contacto de pie en las presas de pie. Descanso: 60 s entre series' where name = 'Estiramiento de Gemelo en Pared - Estatico Pasivo';
update exercises set name = 'Estiramiento de Flexor de Cadera en Pared - Estático Pasivo', description = 'Manten un estiramiento pasivo de flexor de cadera y cuádriceps usando una pared para profundizar el estiramiento durante sujeciones cronometradas. Objetivo: Alargar los flexores de cadera y cuádriceps, mejorando el rango de extensión de cadera para pasos altos, mantle y escalada en pared pronunciada. Descanso: 60 s entre series' where name = 'Estiramiento de Flexor de Cadera en Pared - Estatico Pasivo';
update exercises set name = 'Calentamiento y Vuelta a la Calma', description = 'Una rutina guiada rápida de rotación interna acostado, postura de paloma, estiramiento de isquiotibiales, postura de caballo ISO, rana y estiramiento de gemelo para uso de calentamiento o vuelta a la calma. Objetivo: Mantener la flexibilidad del tren inferior y preparar las articulaciones para la escalada, adecuado como calentamiento previo al entrenamiento o vuelta a la calma posterior.' where name = 'Calentamiento y Vuelta a la Calma';
update exercises set name = 'Estiramiento de Muñeca - Estático Pasivo', description = 'Múltiples series de estiramiento de muñeca pasivo de 60 s. Objetivo: Mejorar la flexibilidad de flexores y extensores de muñeca, apoyando la salud de los dedos y reduciendo el riesgo de lesión por las altas demandas de carga de la escalada. Descanso: 60 s entre series' where name = 'Estiramiento de Muneca - Estatico Pasivo';
update exercises set name = 'F2 Open - Levantamiento - Fácil', description = 'Realiza levantamientos de 7 s en agarre F2 open (front two open hand), a baja intensidad para mantener la salud del tejido en varias series. Objetivo: Mantener la carga en F2 open a baja intensidad para promover la salud del tejido y el confort sin acumular fatiga. Descanso: 60 s entre series' where name = 'F2 Open - Levantamiento - Facil';
update exercises set name = 'F2 Open - Levantamiento - Máximo', description = 'Realizaras levantamientos de 7 s en agarre F2 open, a intensidad casi máxima para fuerza de peak en varias series. Objetivo: Desarrollar la fuerza máxima de dedos en F2 open mediante carga isométrica corta de alta intensidad con recuperación completa. Descanso: 3 min entre series' where name = 'F2 Open - Levantamiento - Maximo';
update exercises set name = 'F2 Open - Levantamiento - Peak', description = 'Completa levantamientos de 5 s en agarre F2 open en varias series. Objetivo: Aumentar la fuerza de peak de dedos en F2 open y el reclutamiento de unidades motoras mediante esfuerzos muy cortos de intensidad máxima. Descanso: 3 min entre series' where name = 'F2 Open - Levantamiento - Peak';
update exercises set name = 'F2 Open - Levantamiento - Fuerza', description = 'Realizaras levantamientos de 10 s en agarre F2 open en varias series. Objetivo: Aumentar la fuerza de dedos en F2 open mediante carga isométrica de alta intensidad a una duración desafiante pero sostenible. Descanso: 3 min entre series' where name = 'F2 Open - Levantamiento - Fuerza';
update exercises set name = 'F3 Half Crimp - Levantamiento - Máximo', description = 'Este entrenamiento se centra en levantamientos de 7 s en agarre F3 Half crimp (front three half crimp), a intensidad casi máxima para fuerza de peak. Objetivo: Desarrollar la fuerza máxima de dedos en F3 Half crimp mediante carga isométrica corta de alta intensidad con recuperación completa. Descanso: 3 min entre series' where name = 'F3 Half Crimp - Levantamiento - Maximo';
update exercises set name = 'F3 Half Crimp - Levantamiento - Fuerza', description = 'Este entrenamiento se centra en levantamientos de 10 s en agarre F3 Half crimp. Objetivo: Aumentar la fuerza de dedos en F3 Half crimp mediante carga isométrica de alta intensidad a una duración desafiante pero sostenible. Descanso: 3 min entre series' where name = 'F3 Half Crimp - Levantamiento - Fuerza';
update exercises set name = 'Levantamientos de Reclutamiento de Flexores de Dedos', description = 'Completaras múltiples series de levantamientos, aumentando progresivamente la intensidad de muy fácil a desafiante. Objetivo: Calentar y reclutar los flexores de dedos antes de un entrenamiento de escalada aumentando gradualmente la carga. Descanso: 2 min entre series' where name = 'Levantamientos de Reclutamiento de Flexores de Dedos';
update exercises set name = 'Half Crimp 4 - Levantamiento - Base', description = 'Realiza levantamientos de 30 s en Half crimp, a intensidad moderada para construir fuerza base en varias series. Objetivo: Construir fuerza base de dedos en Half crimp mediante carga isométrica de mayor duración a intensidad moderada. Descanso: 3 min entre series' where name = 'Half Crimp 4 - Levantamiento - Base';
